#![no_main]

use nssa_core::program::{ChainedCall, PdaSeed};
use risc0_zkvm::serde::to_vec as risc0_to_vec;
use spel_framework::prelude::*;

risc0_zkvm::guest::entry!(main);

/// Program ID of LEZ's built-in authenticated-transfer program, pinned to
/// logos-execution-zone `v0.2.0-rc1` (commit 35d8df0). The constant is
/// generated by `nssa/build.rs` from the compiled auth-transfer ELF, so
/// bumping LEZ requires regenerating this value. See NOTES.md.
const AUTHENTICATED_TRANSFER_ID: [u32; 8] = [
    2825963824, 2676529631, 1444669123, 3434897758, 335722945, 543185525, 4234047734, 3198000137,
];

/// The wall's on-chain state. `#[account_type]` at file top level registers
/// it in the IDL so `spel inspect <wall-pda> --type WhisperState` decodes
/// the bytes into JSON. Must NOT live inside `mod whisper_wall { … }` —
/// the IDL generator only scans file-level items.
#[account_type]
#[derive(Debug, Clone, Default, BorshSerialize, BorshDeserialize)]
pub struct WhisperState {
    pub admin: [u8; 32],
    pub latest_whisper: String,
    pub last_tip: u128,
    pub whisper_count: u64,
    pub total_tips: u128,
}

#[lez_program]
mod whisper_wall {
    #[allow(unused_imports)]
    use super::*;

    /// Claim the wall PDA and mark the caller as admin.
    #[instruction]
    pub fn initialize(
        #[account(init, pda = literal("wall_v2"))]
        mut state: AccountWithMetadata,
        #[account(signer)]
        admin: AccountWithMetadata,
    ) -> SpelResult {
        let initial = WhisperState {
            admin: *admin.account_id.value(),
            latest_whisper: String::new(),
            last_tip: 0,
            whisper_count: 0,
            total_tips: 0,
        };
        let bytes = borsh::to_vec(&initial).map_err(|e| SpelError::SerializationError {
            message: e.to_string(),
        })?;
        state.account.data = bytes.try_into().unwrap();

        Ok(SpelOutput::execute(vec![state, admin], vec![]))
    }

    /// Post a message — free. Only works when the wall is empty.
    /// Once someone tips to overwrite, only paid overwrites can replace the message.
    #[instruction]
    pub fn whisper(
        #[account(mut, pda = literal("wall_v2"))]
        mut state: AccountWithMetadata,
        #[account(signer)]
        signer: AccountWithMetadata,
        msg: String,
    ) -> SpelResult {
        let data: Vec<u8> = state.account.data.clone().into();
        let mut current: WhisperState =
            borsh::from_slice(&data).map_err(|e| SpelError::DeserializationError {
                account_index: 0,
                message: e.to_string(),
            })?;

        if !current.latest_whisper.is_empty() {
            return Err(SpelError::Unauthorized {
                message: "Wall is not empty — use overwrite with a tip".to_string(),
            });
        }

        current.latest_whisper = msg;
        current.whisper_count = current.whisper_count.saturating_add(1);

        let bytes = borsh::to_vec(&current).map_err(|e| SpelError::SerializationError {
            message: e.to_string(),
        })?;
        state.account.data = bytes.try_into().unwrap();

        Ok(SpelOutput::execute(vec![state, signer], vec![]))
    }

    /// Outbid the current whisper. Fails unless `tip > last_tip`.
    /// Emits a `ChainedCall` to `auth-transfer` that debits the signer and
    /// credits the wall PDA by `tip` native tokens — atomic with the state update.
    #[instruction]
    pub fn overwrite(
        #[account(mut, pda = literal("wall_v2"))]
        mut state: AccountWithMetadata,
        #[account(signer)]
        signer: AccountWithMetadata,
        msg: String,
        tip: u128,
    ) -> SpelResult {
        let data: Vec<u8> = state.account.data.clone().into();
        let mut current: WhisperState =
            borsh::from_slice(&data).map_err(|e| SpelError::DeserializationError {
                account_index: 0,
                message: e.to_string(),
            })?;

        if tip <= current.last_tip {
            return Err(SpelError::Unauthorized {
                message: "Tip must exceed the current last_tip".to_string(),
            });
        }

        current.latest_whisper = msg;
        current.last_tip = tip;
        current.whisper_count = current.whisper_count.saturating_add(1);
        current.total_tips = current.total_tips.saturating_add(tip);

        let bytes = borsh::to_vec(&current).map_err(|e| SpelError::SerializationError {
            message: e.to_string(),
        })?;
        state.account.data = bytes.try_into().unwrap();

        // Build the ChainedCall: (sender=signer, recipient=wall).
        // auth-transfer's instruction payload is just `to_vec(&amount)`.
        let ix_data = risc0_to_vec(&tip).map_err(|e| SpelError::SerializationError {
            message: e.to_string(),
        })?;
        let chained = ChainedCall {
            program_id: AUTHENTICATED_TRANSFER_ID,
            instruction_data: ix_data,
            pre_states: vec![signer.clone(), state.clone()],
            pda_seeds: vec![], // signer is a regular account, not a PDA
        };

        Ok(SpelOutput::execute(vec![state, signer], vec![chained]))
    }

    /// Admin-only: transfer the jar's accumulated balance out.
    ///
    /// The wall PDA is owned by this program (claimed via `#[account(init)]`
    /// in `initialize`), so we can decrement its balance directly in the
    /// post-state — no ChainedCall to auth-transfer needed. Increments to
    /// the recipient are allowed for any program (LEZ's rule is
    /// "only owner can DECREASE").
    #[instruction]
    pub fn drain_jar(
        #[account(mut, pda = literal("wall_v2"))]
        mut state: AccountWithMetadata,
        #[account(signer)]
        signer: AccountWithMetadata,
        #[account(mut)]
        mut recipient: AccountWithMetadata,
    ) -> SpelResult {
        let data: Vec<u8> = state.account.data.clone().into();
        let mut current: WhisperState =
            borsh::from_slice(&data).map_err(|e| SpelError::DeserializationError {
                account_index: 0,
                message: e.to_string(),
            })?;

        if signer.account_id.value() != &current.admin {
            return Err(SpelError::Unauthorized {
                message: "Only the admin can drain the jar".to_string(),
            });
        }

        let amount = state.account.balance;
        current.total_tips = 0;

        let bytes = borsh::to_vec(&current).map_err(|e| SpelError::SerializationError {
            message: e.to_string(),
        })?;
        state.account.data = bytes.try_into().unwrap();

        // Direct balance transfer: we own the wall PDA, so we can debit it.
        state.account.balance = 0;
        recipient.account.balance = recipient
            .account
            .balance
            .checked_add(amount)
            .ok_or(SpelError::Overflow {
                operation: "recipient balance add".to_string(),
            })?;

        Ok(SpelOutput::execute(vec![state, signer, recipient], vec![]))
    }

    /// Read-only: returns the wall account unchanged. The user decodes the
    /// data via `spel inspect <wall-pda> --type WhisperState`.
    #[instruction]
    pub fn reveal(
        #[account(pda = literal("wall_v2"))]
        state: AccountWithMetadata,
    ) -> SpelResult {
        Ok(SpelOutput::execute(vec![state], vec![]))
    }
}
